protected <S extends T> Page<S> readPage(TypedQuery<S> query, Class<S> domainClass, Pageable pageable,
			Specification<S> spec) {

		Assert.notNull(spec, "Specification must not be null");

		if (pageable.isPaged()) {
			query.setFirstResult(PageableUtils.getOffsetAsInteger(pageable));
			query.setMaxResults(pageable.getPageSize());
		}

		return PageableExecutionUtils.getPage(query.getResultList(), pageable,
				() -> executeCountQuery(getCountQuery(spec, domainClass)));
	}

@Bean
	@ConditionalOnProperty(SPRINGDOC_SCHEMA_RESOLVE_PROPERTIES)
	@Lazy(false)
	GlobalOpenApiCustomizer propertiesResolverForSchema(OpenAPIService openAPIService) {
		return openApi -> {
			Components components = openApi.getComponents();
			Map<String, Schema> schemas = components.getSchemas();
			if (!CollectionUtils.isEmpty(schemas))
				schemas.values().forEach(schema -> openAPIService.resolveProperties(schema, Locale.getDefault()));
		};
	}

public static ObjectMapper createJson(SpringDocConfigProperties springDocConfigProperties) {
	OpenApiVersion openApiVersion = springDocConfigProperties.getApiDocs().getVersion();
	ObjectMapper objectMapper;
	if (openApiVersion == OpenApiVersion.OPENAPI_3_1)
		objectMapper = ObjectMapperFactory.createJson31();
	else
		objectMapper = ObjectMapperFactory.createJson();

	if (springDocConfigProperties.isWriterWithOrderByKeys())
		sortOutput(objectMapper, springDocConfigProperties);

	return objectMapper;
}

private CacheControl createCacheControl() {
	if (Boolean.TRUE.equals(this.noStore)) {
		return CacheControl.noStore();
	}
	if (Boolean.TRUE.equals(this.noCache)) {
		return CacheControl.noCache();
	}
	if (this.maxAge != null) {
		return CacheControl.maxAge(this.maxAge.getSeconds(), TimeUnit.SECONDS);
	}
	return CacheControl.empty();
}

public EnumSet<DispatcherType> determineDispatcherTypes() {
	if (CollectionUtils.isEmpty(this.dispatcherTypes)) {
		T filter = getFilter();
		Assert.state(filter != null, "'filter' must not be null");
		if (ClassUtils.isPresent("org.springframework.web.filter.OncePerRequestFilter",
				filter.getClass().getClassLoader()) && filter instanceof OncePerRequestFilter) {
			return EnumSet.allOf(DispatcherType.class);
		}
		else {
			return EnumSet.of(DispatcherType.REQUEST);
		}
	}
	return EnumSet.copyOf(this.dispatcherTypes);
}

@Override
	public void addErrorPages(ErrorPage... errorPages) {
		for (ErrorPage errorPage : errorPages) {
			if (errorPage.isGlobal()) {
				this.global = errorPage.getPath();
			}
			else if (errorPage.getStatus() != null) {
				this.statuses.put(errorPage.getStatus().value(), errorPage.getPath());
			}
			else {
				this.exceptions.put(errorPage.getException(), errorPage.getPath());
			}
		}
	}

protected final Map<String, SslBundle> getServerNameSslBundles() {
	Assert.state(this.ssl != null, "'ssl' must not be null");
	return this.ssl.getServerNameBundles()
		.stream()
		.collect(Collectors.toMap(ServerNameSslBundle::serverName, (serverNameSslBundle) -> {
			Assert.state(this.sslBundles != null, "'sslBundles' must not be null");
			return this.sslBundles.getBundle(serverNameSslBundle.bundle());
		}));
}

@Override
	public void onApplicationEvent(WebServerInitializedEvent event) {
		File portFile = getPortFile(event.getApplicationContext());
		try {
			String port = String.valueOf(event.getWebServer().getPort());
			createParentDirectory(portFile);
			FileCopyUtils.copy(port.getBytes(), portFile);
			portFile.deleteOnExit();
		}
		catch (Exception ex) {
			logger.warn(LogMessage.format("Cannot create port file %s", this.file));
		}
	}

@Contract("!null -> !null")
		private @Nullable Set<jakarta.servlet.SessionTrackingMode> unwrap(
				@Nullable Set<Session.SessionTrackingMode> modes) {
			if (modes == null) {
				return null;
			}
			Set<jakarta.servlet.SessionTrackingMode> result = new LinkedHashSet<>();
			for (Session.SessionTrackingMode mode : modes) {
				result.add(jakarta.servlet.SessionTrackingMode.valueOf(mode.name()));
			}
			return result;
		}

private List<String> sortByAnnotation(AutoConfigurationClasses classes, List<String> classNames) {
	List<String> toSort = new ArrayList<>(classNames);
	toSort.addAll(classes.getAllNames());
	Set<String> sorted = new LinkedHashSet<>();
	Set<String> processing = new LinkedHashSet<>();
	while (!toSort.isEmpty()) {
		doSortByAfterAnnotation(classes, toSort, sorted, processing, null);
	}
	sorted.retainAll(classNames);
	return new ArrayList<>(sorted);
}

private Set<String> matchedNamesFrom(Map<String, @Nullable BeanDefinition> namedDefinitions,
			BiPredicate<String, BeanDefinition> filter) {
		Set<String> matchedNames = new LinkedHashSet<>(namedDefinitions.size());
		for (Entry<String, BeanDefinition> namedDefinition : namedDefinitions.entrySet()) {
			if (filter.test(namedDefinition.getKey(), namedDefinition.getValue())) {
				matchedNames.add(namedDefinition.getKey());
			}
		}
		return matchedNames;
	}

private static @Nullable TaskDecorator getTaskDecorator(ObjectProvider<TaskDecorator> taskDecorator) {
	List<TaskDecorator> taskDecorators = taskDecorator.orderedStream().toList();
	if (taskDecorators.size() == 1) {
		return taskDecorators.get(0);
	}
	return (!taskDecorators.isEmpty()) ? new CompositeTaskDecorator(taskDecorators) : null;
}

DefaultConnectionPorts(DockerCliInspectResponse inspectResponse) {
	this.mappings = !isHostNetworkMode(inspectResponse)
			? buildMappingsForNetworkSettings(inspectResponse.networkSettings())
			: buildMappingsForHostNetworking(inspectResponse.config());
	Map<Integer, Integer> portMappings = new HashMap<>();
	this.mappings.forEach((containerPort, hostPort) -> portMappings.put(containerPort.number(), hostPort));
	this.portMappings = Collections.unmodifiableMap(portMappings);
}

private Map<ContainerPort, Integer> buildMappingsForHostNetworking(Config config) {
	if (CollectionUtils.isEmpty(config.exposedPorts())) {
		return Collections.emptyMap();
	}
	Map<ContainerPort, Integer> mappings = new HashMap<>();
	for (String entry : config.exposedPorts().keySet()) {
		ContainerPort containerPort = ContainerPort.parse(entry);
		mappings.put(containerPort, containerPort.number());
	}
	return Collections.unmodifiableMap(mappings);
}

@Override
	public List<Integer> getAll(@Nullable String protocol) {
		List<Integer> hostPorts = new ArrayList<>();
		this.mappings.forEach((containerPort, hostPort) -> {
			if (protocol == null || protocol.equalsIgnoreCase(containerPort.protocol())) {
				hostPorts.add(hostPort);
			}
		});
		return Collections.unmodifiableList(hostPorts);
	}

public static DockerComposeFile of(File file) {
	Assert.notNull(file, "'file' must not be null");
	Assert.isTrue(file.exists(), () -> "'file' [%s] must exist".formatted(file));
	Assert.isTrue(file.isFile(), () -> "'file' [%s] must be a normal file".formatted(file));
	return new DockerComposeFile(Collections.singletonList(file));
}

private static void handleComponentSchemaTypes(OpenAPI openAPI) {
	if (openAPI.getComponents() == null || openAPI.getComponents().getSchemas() == null) {
		return;
	}
	for (Schema<?> schema : openAPI.getComponents().getSchemas().values()) {
		SpringDocUtils.fixNullOnlyAdditionalProperties(schema);
	}
}

protected AbstractDependsOnBeanFactoryPostProcessor(Class<?> beanClass,
			@Nullable Class<? extends FactoryBean<?>> factoryBeanClass, String... dependsOn) {
		this.beanClass = beanClass;
		this.factoryBeanClass = factoryBeanClass;
		this.dependsOn = (beanFactory) -> new HashSet<>(Arrays.asList(dependsOn));
	}

private String getBeanDescription(NoSuchBeanDefinitionException cause) {
	if (cause.getResolvableType() != null) {
		Class<?> type = extractBeanType(cause.getResolvableType());
		return "a bean of type '" + type.getName() + "'";
	}
	return "a bean named '" + cause.getBeanName() + "'";
}

private List<UserConfigurationResult> getUserConfigurationResults(NoSuchBeanDefinitionException cause) {
	ResolvableType type = cause.getResolvableType();
	if (type == null) {
		return Collections.emptyList();
	}
	String[] beanNames = BeanFactoryUtils.beanNamesForTypeIncludingAncestors(this.beanFactory, type);
	return Arrays.stream(beanNames)
		.map((beanName) -> new UserConfigurationResult(getFactoryMethodMetadata(beanName),
				this.beanFactory.getBean(beanName).equals(null)))
		.toList();
}

@Override
	public @Nullable ExitStatus afterStep(StepExecution stepExecution) {
		for (Iterator<StepExecutionListener> iterator = list.reverse(); iterator.hasNext();) {
			StepExecutionListener listener = iterator.next();
			ExitStatus close = listener.afterStep(stepExecution);
			if (close != null) {
				stepExecution.setExitStatus(stepExecution.getExitStatus().and(close));
			}
		}
		return stepExecution.getExitStatus();
	}

protected void deregisterJdbcDrivers(ServletContext servletContext) {
	for (Driver driver : Collections.list(DriverManager.getDrivers())) {
		if (driver.getClass().getClassLoader() == servletContext.getClassLoader()) {
			try {
				DriverManager.deregisterDriver(driver);
			}
			catch (SQLException ex) {
				// Continue
			}
		}
	}
}

private Set<BeanType> resolveWhenPossible(Set<String> classNames) {
	if (classNames.isEmpty()) {
		return Collections.emptySet();
	}
	Set<BeanType> resolved = new LinkedHashSet<>(classNames.size());
	for (String className : classNames) {
		try {
			Class<?> type = resolve(className, this.context.getClassLoader());
			resolved.add(new BeanType(className, ResolvableType.forRawClass(type)));
		}
		catch (ClassNotFoundException | NoClassDefFoundError ex) {
			resolved.add(new BeanType(className, ResolvableType.NONE));
		}
	}
	return resolved;
}

public final @Nullable File getValidDirectory() {
	File file = this.directory;
	file = (file != null) ? file : getWarFileDocumentRoot();
	file = (file != null) ? file : getExplodedWarFileDocumentRoot();
	file = (file != null) ? file : getCommonDocumentRoot();
	if (file == null && this.logger.isDebugEnabled()) {
		logNoDocumentRoots();
	}
	else if (this.logger.isDebugEnabled()) {
		this.logger.debug("Document root: " + file);
	}
	return file;
}

final @Nullable File getExplodedWarFileDocumentRoot(@Nullable File codeSourceFile) {
	if (this.logger.isDebugEnabled()) {
		this.logger.debug("Code archive: " + codeSourceFile);
	}
	if (codeSourceFile != null && codeSourceFile.exists()) {
		String path = codeSourceFile.getAbsolutePath();
		int webInfPathIndex = path.indexOf(File.separatorChar + "WEB-INF" + File.separatorChar);
		if (webInfPathIndex >= 0) {
			path = path.substring(0, webInfPathIndex);
			return new File(path);
		}
	}
	return null;
}

List<URL> getUrls() {
	ClassLoader classLoader = getClass().getClassLoader();
	if (classLoader instanceof URLClassLoader urlClassLoader) {
		return getUrlsFrom(urlClassLoader.getURLs());
	}
	else {
		return getUrlsFrom(Stream.of(ManagementFactory.getRuntimeMXBean().getClassPath().split(File.pathSeparator))
			.map(this::toUrl)
			.toArray(URL[]::new));
	}
}

@Contract("_, !null, _, _ -> !null")
		public static <R> @Nullable R map(@Nullable ClientAuth clientAuth, @Nullable R none, R want, R need) {
			if (clientAuth == null) {
				return none;
			}
			return switch (clientAuth) {
				case NONE -> none;
				case WANT -> want;
				case NEED -> need;
			};
		}

private List<String> getMatchingBeans(Map<String, @Nullable BeanDefinition> beanDefinitions,
			Predicate<@Nullable BeanDefinition> test) {
		List<String> matches = new ArrayList<>();
		for (Entry<String, @Nullable BeanDefinition> namedBeanDefinition : beanDefinitions.entrySet()) {
			if (test.test(namedBeanDefinition.getValue())) {
				matches.add(namedBeanDefinition.getKey());
			}
		}
		return matches;
	}

private void logExclusions(ConditionEvaluationReport report, StringBuilder message) {
	message.append(String.format("Exclusions:%n"));
	message.append(String.format("-----------%n"));
	if (report.getExclusions().isEmpty()) {
		message.append(String.format("%n    None%n"));
	}
	else {
		for (String exclusion : report.getExclusions()) {
			message.append(String.format("%n    %s%n", exclusion));
		}
	}
	message.append(String.format("%n%n"));
}
